export default () => {
    return new Promise((resolve, reject) => {
        let contributors = [];

        window.fetch("https://thebastionbot.herokuapp.com/github/contributors", {
            headers: {
                "UserAgent": "The Bastion Bot Website (https://bastionbot.org)",
            },
        })
        .then(res => res.json())
        .then(data => {
            for (let contributor of Object.keys(data)) {
                if (data[contributor].type === "User") {
                    contributors.push({
                        id: contributor,
                        username: data[contributor].login,
                        url: data[contributor].url,
                        avatar: data[contributor].avatar,
                        contributions: data[contributor].contributions,
                        type: data[contributor].type,
                    });
                }
            }

            resolve(contributors);
        })
        .catch(e => reject(e));
    });
};
