import React from "react";

import Layout from "../layouts/default";
import PageHeader from "../components/PageHeader";
import PageContent from "../components/Content";
import Loader from "../components/Loader";
import Card from "../components/Card";
import fetchGitHubContributors from "../utils/fetchGitHubContributors";

let cachedContributors;

export default class Contributors extends React.Component {
    constructor(props) {
        super(props);

        this.state = {
            contributors: [],
        };
    }

    componentDidMount() {
        if (cachedContributors) {
            this.setState({ contributors: cachedContributors });
        } else {
            fetchGitHubContributors().then(fetchedContributors => {
                cachedContributors = fetchedContributors;

                this.setState({ contributors: fetchedContributors });
            }).catch(console.error);
        }
    }

    render () {
        return (
            <Layout
                title="Contributors"
                description="These are all the cool people who have contributed (code, design, etc.) to The Bastion Bot Project!"
                image="https://resources.bastionbot.org/og/a579602249857d28777d7aff1cbc5af3.jpg"
            >
                <PageHeader />

                <PageContent>
                    <div css={{
                        textAlign: "center",
                        marginBottom: 50,
                    }}>
                        <h1>Contributors</h1>
                        <p>
                            All the users who have contributed code to The Bastion Bot Project.
                        </p>
                        <p>
                            Users who frequently contribute to the project will be invited to be a
                            member of the GitHub organization.
                        </p>
                    </div>

                    <div css={{
                        display: "flex",
                        flexWrap: "wrap",
                        justifyContent: "center",
                    }}>
                        {
                            this.state.contributors.length
                            ? this.state.contributors.sort((a, b) => b.contributions - a.contributions).map((user, i) => (
                                <Card
                                    key={ i }
                                    title={ user.username === "k3rn31p4nic" ? user.username : null }
                                    tagline={ user.username === "k3rn31p4nic" ? null : user.username }
                                    description={ user.contributions + " Contributions" }
                                    // image={ user.avatar }
                                    link={ user.username === "k3rn31p4nic" ? user.url : null }
                                    minWidth={ 400 }
                                    maxWidth={ 400 }
                                    center={ true }
                                    middle={ true }
                                    dark={ true }
                                />
                            ))
                            : <Loader />
                        }
                    </div>
                </PageContent>
            </Layout>
        );
    }
};
